import { Component, OnInit } from "@angular/core";
import { Router } from "@angular/router";
import { FormsModule } from "@angular/forms";
import { CommonModule } from "@angular/common";
import { MovieService } from "../../services/movie.service";
import { AuthService } from "../../services/auth.service";
import { Movie } from "../../models/interfaces";

@Component({
  selector: "app-movie-list",
  standalone: true,
  imports: [FormsModule, CommonModule],
  templateUrl: "./movie-list.component.html",
  styleUrls: ["./movie-list.component.css"],
})
export class MovieListComponent implements OnInit {
  movies: Movie[] = [];
  searchQuery = "";
  genreFilter = "";
  categoryFilter = "";
  yearFilter = "";
  categoryOptions = [
    { value: "", label: "All Categories" },
    { value: "movie", label: "Movies" },
    { value: "cartoon", label: "Cartoons" },
    { value: "bollywood", label: "Bollywood Movies" },
    { value: "series", label: "Series" },
  ];
  errorMessage = "";
  loading = false;

  constructor(
    private movieService: MovieService,
    private authService: AuthService,
    private router: Router,
  ) {}

  ngOnInit(): void {
    this.movieService.movies$.subscribe(
      (movies) => {
        this.movies = movies;
        this.loading = false;
      },
      (error) => {
        this.errorMessage = "Failed to load movies";
        this.loading = false;
      },
    );
    this.loadMovies();
  }

  loadMovies(): void {
    this.loading = true;
    this.errorMessage = "";
    this.movieService.loadMovies();
  }

  // Event 1: Search movies
  onSearch(): void {
    this.movieService.loadMovies(
      this.searchQuery.trim(),
      this.genreFilter.trim(),
      this.categoryFilter,
      this.yearFilter.trim(),
    );
  }

  // Event 2: Filter by genre
  onFilterByGenre(): void {
    this.movieService.loadMovies(
      this.searchQuery.trim(),
      this.genreFilter.trim(),
      this.categoryFilter,
      this.yearFilter.trim(),
    );
  }

  // Event 3: Advanced category/year filter
  onApplyAdvancedFilters(): void {
    this.movieService.loadMovies(
      this.searchQuery.trim(),
      this.genreFilter.trim(),
      this.categoryFilter,
      this.yearFilter.trim(),
    );
  }

  // Event 4: Reset all filters
  onResetFilters(): void {
    this.searchQuery = "";
    this.genreFilter = "";
    this.categoryFilter = "";
    this.yearFilter = "";
    this.movieService.loadMovies();
  }

  // Event 5: Navigate to movie details
  onViewDetails(movieId: number): void {
    this.router.navigate(["/movie", movieId]);
  }

  onPosterError(movie: Movie): void {
    movie.poster_url = "";
  }

  // Event 6: Navigate to favorites
  onViewFavorites(): void {
    this.router.navigate(["/favorites"]);
  }

  onLogout(): void {
    this.authService.logout().subscribe(
      () => {
        this.authService.performLogout();
        this.router.navigate(["/login"]);
      },
      (error) => {
        this.authService.performLogout();
        this.router.navigate(["/login"]);
      },
    );
  }
}
<div class="movie-list-container">
  <nav class="navbar">
    <div class="navbar-brand">
      <h1>🎬 Movie Catalog</h1>
    </div>
    <div class="navbar-menu">
      <button class="btn-link" (click)="onViewFavorites()">❤️ Favorites</button>
      <button class="btn-logout" (click)="onLogout()">Logout</button>
    </div>
  </nav>

  <div class="search-section">
    <div class="form-group">
      <input
        type="text"
        [(ngModel)]="searchQuery"
        placeholder="Search movies by title..."
        class="search-input"
      />
      <button class="btn-search" (click)="onSearch()">Search</button>
    </div>

    <div class="form-group">
      <input
        type="text"
        [(ngModel)]="genreFilter"
        placeholder="Filter by genre..."
        class="search-input"
      />
      <button class="btn-search" (click)="onFilterByGenre()">Filter</button>
    </div>

    <div class="form-group">
      <select [(ngModel)]="categoryFilter" class="search-input">
        <option *ngFor="let option of categoryOptions" [value]="option.value">
          {{ option.label }}
        </option>
      </select>
      <input
        type="number"
        [(ngModel)]="yearFilter"
        placeholder="Year (e.g. 2007)"
        min="1900"
        max="2100"
        class="search-input year-input"
      />
      <button class="btn-search" (click)="onApplyAdvancedFilters()">
        Apply
      </button>
      <button class="btn-reset" (click)="onResetFilters()">Reset</button>
    </div>
  </div>

  <div class="error-message" *ngIf="errorMessage">
    {{ errorMessage }}
  </div>

  <div class="loading" *ngIf="loading">Loading movies...</div>

  <div class="movies-grid">
    <div class="movie-card" *ngFor="let movie of movies">
      <ng-container *ngIf="movie.poster_url; else noImage">
        <img
          [src]="movie.poster_url"
          [alt]="movie.title"
          class="movie-poster"
          (error)="onPosterError(movie)"
        />
      </ng-container>
      <ng-template #noImage>
        <div class="movie-poster-placeholder">No Image</div>
      </ng-template>
      <div class="movie-info">
        <h3>{{ movie.title }}</h3>
        <p class="year">{{ movie.release_date | slice: 0 : 4 }}</p>
        <p class="genre">{{ movie.genre }}</p>
        <div class="rating">
          <span class="stars">⭐ {{ movie.rating.toFixed(1) }}</span>
          <span class="count">({{ movie.reviews_count }} reviews)</span>
        </div>
        <p class="description">{{ movie.description | slice: 0 : 120 }}...</p>
        <button class="btn-view" (click)="onViewDetails(movie.id)">
          View Details
        </button>
      </div>
    </div>
  </div>

  <div class="no-results" *ngIf="movies.length === 0 && !loading">
    <p>No movies found. Try adjusting your search or filters.</p>
  </div>
</div>
